 1→// ── Port & Param types ──────────────────────────────────────────────
 2→
 3→export enum PortType {
 4→  TABLE = "TABLE",
 5→  MODEL = "MODEL",
 6→  METRICS = "METRICS",
 7→  ARRAY = "ARRAY",
 8→  VALUE = "VALUE",
 9→  TENSOR = "TENSOR",
10→}
11→
12→export const PORT_COLORS: Record<PortType, string> = {
13→  [PortType.TABLE]: "#9CA3AF",
14→  [PortType.MODEL]: "#22C55E",
15→  [PortType.METRICS]: "#EAB308",
16→  [PortType.ARRAY]: "#3B82F6",
17→  [PortType.VALUE]: "#A855F7",
