 58→export function NodeLibrarySidebar({ definitions }: SidebarProps) {
 59→  const [search, setSearch] = useState("");
 60→
 61→  const filtered = definitions.filter(
 62→    (d) =>
 63→      d.label.toLowerCase().includes(search.toLowerCase()) ||
 64→      d.category.toLowerCase().includes(search.toLowerCase()),
 65→  );
 66→
 67→  // Group by category
 68→  const grouped = filtered.reduce<Record<string, NodeDefinition[]>>(
 69→    (acc, def) => {
 70→      (acc[def.category] ??= []).push(def);
 71→      return acc;
 72→    },
 73→    {},
 74→  );
 75→
 76→  return (
 77→    <div className="flex h-full flex-col">
 78→      <div className="border-b border-border px-4 py-3">
 79→        <h2 className="mb-2 text-sm font-semibold text-foreground">
 80→          Node Library
 81→        </h2>
 82→        <input
 83→          type="text"
 84→          placeholder="Search nodes..."
 85→          value={search}
 86→          onChange={(e) => setSearch(e.target.value)}
 87→          className="w-full rounded-md border border-border bg-input px-2.5 py-1.5 text-xs text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
 88→        />
 89→      </div>
 90→      <div className="flex-1 overflow-y-auto px-4 py-3">
 91→        {Object.entries(grouped).map(([category, defs]) => (
 92→          <div key={category} className="mb-4">
 93→            <h3 className="mb-1.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
 94→              {category}
 95→            </h3>
 96→            <div className="flex flex-col gap-1.5">
 97→              {defs.map((def) => (
 98→                <NodeTypeCard key={def.type} definition={def} />
 99→              ))}
100→            </div>
101→          </div>
102→        ))}
103→        {filtered.length === 0 && (
104→          <p className="text-xs text-muted-foreground">No nodes found.</p>
105→        )}
106→      </div>
107→    </div>
108→  );
109→}
