import { useCallback } from "react";
import type { Node } from "@xyflow/react";
import type { NodeCardData, NodeTab } from "@/components/Canvas";
import type { NodeParam } from "@/lib/types";

export interface RightPanelProps {
  node: Node<NodeCardData> | null;
  activeTab: NodeTab;
  onTabChange: (tab: NodeTab) => void;
  onParamsChange: (params: Record<string, string | number | boolean>) => void;
  onCodeChange: (code: string) => void;
  onClose?: () => void;
}

const TABS: NodeTab[] = ["params", "code", "output"];

function ParamEditor({
  param,
  value,
  onChange,
}: {
  param: NodeParam;
  value: string | number | boolean;
  onChange: (name: string, value: string | number | boolean) => void;
}) {
  switch (param.type) {
    case "select":
      return (
        <select
          className="w-full rounded border border-border bg-secondary px-2 py-1 text-xs text-foreground"
          value={String(value)}
          onChange={(e) => onChange(param.name, e.target.value)}
        >
          {param.options?.map((opt) => (
            <option key={opt} value={opt}>
              {opt}
            </option>
          ))}
        </select>
      );
    case "slider":
      return (
        <div className="flex items-center gap-2">
          <input
            type="range"
            className="flex-1"
            min={param.min ?? 0}
            max={param.max ?? 100}
            step={param.step ?? 1}
            value={Number(value)}
            onChange={(e) => onChange(param.name, Number(e.target.value))}
          />
          <span className="w-12 text-right text-xs text-muted-foreground">
            {value}
          </span>
        </div>
      );
    case "toggle":
      return (
        <button
          type="button"
          className={`h-5 w-9 rounded-full transition-colors ${
            value ? "bg-blue-500" : "bg-zinc-600"
          }`}
          onClick={() => onChange(param.name, !value)}
        >
          <span
            className={`block h-4 w-4 rounded-full bg-white transition-transform ${
              value ? "translate-x-4" : "translate-x-0.5"
            }`}
          />
        </button>
      );
    case "text":
    default:
      return (
        <input
          type="text"
          className="w-full rounded border border-border bg-secondary px-2 py-1 text-xs text-foreground"
          value={String(value ?? "")}
          onChange={(e) => onChange(param.name, e.target.value)}
        />
      );
  }
}

function ParamsPanel({
  node,
  onParamsChange,
}: {
  node: Node<NodeCardData>;
  onParamsChange: (params: Record<string, string | number | boolean>) => void;
}) {
  const { definition, params } = node.data;

  const handleChange = useCallback(
    (name: string, value: string | number | boolean) => {
      onParamsChange({ ...params, [name]: value });
    },
    [params, onParamsChange],
  );

  if (definition.params.length === 0) {
    return (
      <p className="text-xs text-muted-foreground">
        This node has no parameters.
      </p>
    );
  }

  return (
    <div className="flex flex-col gap-3">
      {definition.params.map((p) => (
        <div key={p.name}>
          <label className="mb-1 block text-xs font-medium text-foreground">
            {p.name}
          </label>
          <ParamEditor
            param={p}
            value={params[p.name] ?? p.default}
            onChange={handleChange}
          />
        </div>
      ))}
    </div>
  );
}

function CodePanel({
  node,
  onCodeChange,
}: {
  node: Node<NodeCardData>;
  onCodeChange: (code: string) => void;
}) {
  const code = node.data.code ?? node.data.definition.default_code ?? "";
  return (
    <textarea
      className="h-64 w-full resize-y rounded border border-border bg-secondary p-2 font-mono text-xs text-foreground"
      value={code}
      onChange={(e) => onCodeChange(e.target.value)}
      spellCheck={false}
    />
  );
}

function OutputPanel() {
  return (
    <p className="text-xs text-muted-foreground">
      No output yet. Run the pipeline to see results.
    </p>
  );
}

export function RightPanel({
  node,
  activeTab,
  onTabChange,
  onParamsChange,
  onCodeChange,
  onClose,
}: RightPanelProps) {
  if (!node) {
    return (
      <div className="flex h-full flex-col p-4 text-muted-foreground">
        <p className="text-xs">Select a node to view its properties.</p>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-border px-4 py-3">
        <h2 className="text-sm font-semibold text-foreground">
          {node.data.label}
        </h2>
        {onClose && (
          <button
            type="button"
            onClick={onClose}
            className="text-muted-foreground hover:text-foreground"
          >
            ✕
          </button>
        )}
      </div>

      {/* Tabs */}
      <div className="flex border-b border-border">
        {TABS.map((tab) => (
          <button
            key={tab}
            type="button"
            onClick={() => onTabChange(tab)}
            className={`flex-1 py-2 text-xs font-medium capitalize transition-colors ${
              activeTab === tab
                ? "border-b-2 border-blue-500 text-foreground"
                : "text-muted-foreground hover:text-foreground"
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4">
        {activeTab === "params" && (
          <ParamsPanel node={node} onParamsChange={onParamsChange} />
        )}
        {activeTab === "code" && (
          <CodePanel node={node} onCodeChange={onCodeChange} />
        )}
        {activeTab === "output" && <OutputPanel />}
      </div>
    </div>
  );
}

